{"filter":false,"title":"tool_b2_step1.py","tooltip":"/evaluation/tool_b2_step1.py","undoManager":{"mark":0,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":128,"column":0},"action":"insert","lines":["# evaluation/tool_b2_step1.py","from __future__ import annotations","","from dataclasses import dataclass","from typing import Any, Dict, List, Sequence, Tuple","","import pandas as pd","","from evaluation.loader import TrialRecord","from evaluation.text_normalize import normalize_text","","","@dataclass","class ToolB2Step1Outputs:","    # sample_id × turn_stats","    turn_stats_df: pd.DataFrame","","    # sample_id × turn × (question, answer)","    qa_pairs_df: pd.DataFrame","","    # 全体統計（平均/最小/最大など）","    summary: Dict[str, Any]","","","def _is_nonempty(text: str | None) -> bool:","    return bool(text and str(text).strip())","","","def run_tool_b2_step1_extract_qa(","    trials: Sequence[TrialRecord],",") -> ToolB2Step1Outputs:","    \"\"\"","    Tool B2 Step1:","    - 対話ログから Q/A ペア（turn単位）を抽出","    - 正規化（text_normalize）を適用","    - sample_id（zip名）単位でターン数統計を算出","","    NOTE:","    - この段階では LLM分類はしない（質問妥当性の前処理）","    \"\"\"","","    qa_rows: List[Dict[str, Any]] = []","    stats_rows: List[Dict[str, Any]] = []","","    for t in trials:","        sample_id = t.zip_name","","        # loader.py が turn 単位で qa_pairs を作っている前提","        pairs = t.qa_pairs","","        q_count = 0","        a_count = 0","        complete_pairs = 0","","        for p in pairs:","            q_norm = normalize_text(p.question) if p.question else \"\"","            a_norm = normalize_text(p.answer) if p.answer else \"\"","","            q_has = _is_nonempty(q_norm)","            a_has = _is_nonempty(a_norm)","","            if q_has:","                q_count += 1","            if a_has:","                a_count += 1","            if q_has and a_has:","                complete_pairs += 1","","            # 1行＝1turn","            qa_rows.append(","                {","                    \"sample_id\": sample_id,","                    \"turn\": p.turn,","                    \"question\": q_norm if q_has else \"\",","                    \"answer\": a_norm if a_has else \"\",","                    \"has_question\": int(q_has),","                    \"has_answer\": int(a_has),","                    \"is_complete_pair\": int(q_has and a_has),","                }","            )","","        total_turns = len(pairs)","","        stats_rows.append(","            {","                \"sample_id\": sample_id,","                \"total_turns\": total_turns,          # loader上のturn数（turnキーがあるもの）","                \"question_turns\": q_count,           # 質問があるturn数","                \"answer_turns\": a_count,             # 回答があるturn数","                \"complete_pairs\": complete_pairs,    # Q/A揃い","                \"missing_question_turns\": total_turns - q_count,","                \"missing_answer_turns\": total_turns - a_count,","            }","        )","","    qa_pairs_df = pd.DataFrame(qa_rows)","    turn_stats_df = pd.DataFrame(stats_rows)","","    # サンプル単位のターン数統計（平均/最小/最大）","    if not turn_stats_df.empty:","        turns_list = turn_stats_df[\"question_turns\"].tolist()","        summary = {","            \"n_samples\": int(len(turn_stats_df)),","            # B2では「質問数（question_turns）」をターン数の代表にするのが自然","            \"question_turns_mean\": float(turn_stats_df[\"question_turns\"].mean()),","            \"question_turns_min\": int(turn_stats_df[\"question_turns\"].min()),","            \"question_turns_max\": int(turn_stats_df[\"question_turns\"].max()),","            # 補助：complete_pairs も見ておくとデータ品質が分かる","            \"complete_pairs_mean\": float(turn_stats_df[\"complete_pairs\"].mean()),","            \"complete_pairs_min\": int(turn_stats_df[\"complete_pairs\"].min()),","            \"complete_pairs_max\": int(turn_stats_df[\"complete_pairs\"].max()),","        }","    else:","        summary = {","            \"n_samples\": 0,","            \"question_turns_mean\": 0.0,","            \"question_turns_min\": 0,","            \"question_turns_max\": 0,","            \"complete_pairs_mean\": 0.0,","            \"complete_pairs_min\": 0,","            \"complete_pairs_max\": 0,","        }","","    return ToolB2Step1Outputs(","        turn_stats_df=turn_stats_df,","        qa_pairs_df=qa_pairs_df,","        summary=summary,","    )",""],"id":1}]]},"ace":{"folds":[],"scrolltop":1440,"scrollleft":0,"selection":{"start":{"row":0,"column":0},"end":{"row":128,"column":0},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":{"row":95,"state":"start","mode":"ace/mode/python"}},"timestamp":1768885899057,"hash":"4438264fc138ad4400ee45841622d89cb48241d8"}